Below is a Perl script that demonstrates how to extract specific text (like the date and author) and table information from a PDF file. For simplicity, let's assume the date and author are in the first page's metadata and the tables are in plain text format.

```perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;
use Scalar::Util 'looks_like_number';

sub extract_text {
    my ($page) = @_;
    my $text = '';
    foreach my $line ($page->textlines) {
        $text .= $line->text . "\n";
    }
    return $text;
}

sub extract_date_author {
    my ($pdf) = @_;
    my $info = $pdf->info;
    my ($date, $author);
    if (defined $info->{/ModDate}) {
        $date = $info->{/ModDate};
    }
    if (defined $info->{/Author}) {
        $author = $info->{/Author};
    }
    return ($date, $author);
}

sub extract_tables {
    my ($page) = @_;
    my $text = extract_text($page);
    my $csv = Text::CSV->new({ binary => 1 });
    my @tables = [];
    while ($text =~ m{
        (?:
            (?<table>[\s\S]*?)
        )
        (?=.*?\n\s*[-\w\s]+\n\s*)
    }g) {
        my $table_text = $+{table};
        my @rows = split /\n/, $table_text;
        my @table;
        foreach my $row (@rows) {
            my @fields = $csv->fields($row);
            push @table, \@fields if @fields;
        }
        push @tables, \@table;
    }
    return @tables;
}

